public boolean validateSalesId(SalesIdOrig _salesIdFromExcel)
{
    boolean ret;
    SalesParmSubTable salesParmSubTableLoc = this.orig();

    if(salesParmSubTableLoc.OrigSalesId && _salesIdFromExcel && salesParmSubTableLoc.OrigSalesId == _salesIdFromExcel)
    {
        ret = true;
    }
    else
    {
        checkFailed("Imported sales agreement Id doesn't match with the current sales agreement Id");
        ret = false;
    }

    return ret;
}
